import React, { useState, useEffect, useRef } from 'react';

const API = process.env.REACT_APP_API || 'http://localhost:5001';

function useCountUp(target, duration = 2000, start = false) {
  const [val, setVal] = useState(0);
  useEffect(() => {
    if (!start) return;
    let s = null;
    const step = (ts) => {
      if (!s) s = ts;
      const p = Math.min((ts - s) / duration, 1);
      setVal(Math.floor(p * target));
      if (p < 1) requestAnimationFrame(step);
    };
    requestAnimationFrame(step);
  }, [start, target, duration]);
  return val;
}

function useInView(ref, threshold = 0.15) {
  const [inView, setInView] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setInView(true); }, { threshold });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, [ref, threshold]);
  return inView;
}

function Icon({ name, size = 24, style = {} }) {
  return <span className="material-symbols-outlined" style={{ fontSize: size, lineHeight: 1, ...style }}>{name}</span>;
}

function StatCounter({ value, suffix = '', label, inView }) {
  const num = useCountUp(value, 1800, inView);
  return (
    <div style={{ textAlign: 'center' }}>
      <div style={{ fontSize: 48, fontWeight: 900, color: '#fff', fontFamily: 'Manrope,sans-serif', lineHeight: 1, letterSpacing: '-0.02em' }}>
        {num}{suffix}
      </div>
      <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.6)', marginTop: 8, fontWeight: 700, letterSpacing: '0.1em', textTransform: 'uppercase' }}>{label}</div>
    </div>
  );
}

const FALLBACK_NOTICES = [
  { _id:'1', createdAt: new Date('2026-03-20'), title: 'Annual Sports Day – April 5th', tag: 'Event' },
  { _id:'2', createdAt: new Date('2026-03-15'), title: 'Parent-Teacher Meeting scheduled for March 28th', tag: 'Important' },
  { _id:'3', createdAt: new Date('2026-03-10'), title: 'Summer vacation: May 15 – June 30', tag: 'Holiday' },
  { _id:'4', createdAt: new Date('2026-03-05'), title: 'New session 2025–26 admissions open', tag: 'Admission' },
];

const ACADEMICS = [
  { icon: 'menu_book', label: 'Nursery & KG', desc: 'Play-based early learning with phonics, numeracy, and creative arts.' },
  { icon: 'calculate', label: 'Primary (I–V)', desc: 'Strong foundation in Maths, Science, English, Hindi, and EVS.' },
  { icon: 'science', label: 'Middle (VI–VIII)', desc: 'Conceptual depth in all subjects with project-based learning.' },
  { icon: 'sports_soccer', label: 'Co-Curricular', desc: 'Sports, art, music, and cultural activities for holistic growth.' },
];

const VALUES = [
  { icon: 'emoji_events', color: '#f59e0b', bg: '#fffbeb', label: 'Excellence', desc: '100% annual results with consistent academic achievement.' },
  { icon: 'diversity_3', color: '#8b5cf6', bg: '#f5f3ff', label: 'Inclusivity', desc: 'A welcoming environment for every child to thrive.' },
  { icon: 'psychology', color: '#0ea5e9', bg: '#f0f9ff', label: 'Critical Thinking', desc: 'Encouraging curiosity, reasoning, and problem-solving.' },
  { icon: 'favorite', color: '#ef4444', bg: '#fff1f2', label: 'Care & Values', desc: 'Nurturing character, discipline, and moral values.' },
];

export default function LandingPage() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const [regOpen, setRegOpen] = useState(false);
  const [brochureOpen, setBrochureOpen] = useState(false);
  const [regForm, setRegForm] = useState({ name: '', phone: '', email: '' });
  const [regError, setRegError] = useState('');
  const [regDone, setRegDone] = useState(false);
  const [regLoading, setRegLoading] = useState(false);

  const statsRef = useRef(null);
  const statsInView = useInView(statsRef, 0.2);

  // Scroll listener for navbar
  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 60);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  // Brochure popup after 5s
  useEffect(() => {
    const t = setTimeout(() => setBrochureOpen(true), 5000);
    return () => clearTimeout(t);
  }, []);

  // Scroll-reveal
  useEffect(() => {
    const els = document.querySelectorAll('.reveal');
    const obs = new IntersectionObserver((entries) => {
      entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('revealed'); });
    }, { threshold: 0.1 });
    els.forEach(el => obs.observe(el));
    return () => obs.disconnect();
  }, []);

  const scrollTo = (id) => {
    setMenuOpen(false);
    document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });
  };

  const handleReg = async (e) => {
    e.preventDefault();
    setRegError('');
    if (!regForm.name.trim()) return setRegError('Student name is required.');
    if (!/^\d{10}$/.test(regForm.phone)) return setRegError('Enter a valid 10-digit phone number.');
    setRegLoading(true);
    try {
      const res = await fetch(`${API}/api/admissions`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(regForm),
      });
      if (!res.ok) throw new Error();
      setRegDone(true);
    } catch {
      setRegError('Something went wrong. Please try again.');
    } finally {
      setRegLoading(false);
    }
  };

  const closeReg = () => { setRegOpen(false); setRegDone(false); setRegForm({ name: '', phone: '', email: '' }); setRegError(''); };

  const NAV_LINKS = ['About', 'Academics', 'Notices', 'Contact'];

  return (
    <div style={{ fontFamily: "'Inter', sans-serif", color: '#1e293b', overflowX: 'hidden' }}>
      <style>{`
        @keyframes fadeUp { from { opacity:0; transform:translateY(28px); } to { opacity:1; transform:none; } }
        @keyframes float { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-12px)} }
        @keyframes pulse-ring { 0%{transform:scale(1);opacity:0.6} 100%{transform:scale(1.5);opacity:0} }
        @keyframes shimmer { 0%{background-position:-200% 0} 100%{background-position:200% 0} }
        .reveal { opacity:0; transform:translateY(24px); transition:opacity 0.6s ease, transform 0.6s ease; }
        .reveal.revealed { opacity:1; transform:none; }
        .reveal-d1 { transition-delay:0.1s; }
        .reveal-d2 { transition-delay:0.2s; }
        .reveal-d3 { transition-delay:0.3s; }
        .reveal-d4 { transition-delay:0.4s; }
        .nav-link { position:relative; color:rgba(255,255,255,0.85); text-decoration:none; font-size:13px; font-weight:600; letter-spacing:0.02em; padding:4px 0; transition:color 0.2s; }
        .nav-link::after { content:''; position:absolute; bottom:-2px; left:0; width:0; height:2px; background:#fbbf24; border-radius:2px; transition:width 0.25s ease; }
        .nav-link:hover { color:#fff; }
        .nav-link:hover::after { width:100%; }
        .nav-link-dark { color:#334155; }
        .nav-link-dark:hover { color:#1960a3; }
        .nav-link-dark::after { background:#1960a3; }
        .hero-orb { position:absolute; border-radius:50%; filter:blur(80px); pointer-events:none; }
        .card-hover { transition:transform 0.25s ease, box-shadow 0.25s ease; }
        .card-hover:hover { transform:translateY(-6px); box-shadow:0 20px 50px rgba(0,32,69,0.12); }
        .notice-row:hover { background:#f8faff; }
        .reg-btn { background:linear-gradient(135deg,#fbbf24,#f59e0b); color:#1e293b; border:none; padding:10px 22px; border-radius:50px; font-size:13px; font-weight:800; cursor:pointer; transition:all 0.2s; box-shadow:0 4px 14px rgba(251,191,36,0.4); letter-spacing:0.02em; }
        .reg-btn:hover { transform:translateY(-2px); box-shadow:0 8px 24px rgba(251,191,36,0.5); }
        .hero-cta { display:inline-flex; align-items:center; gap:8px; padding:14px 32px; border-radius:50px; font-size:15px; font-weight:700; cursor:pointer; transition:all 0.25s; border:none; }
        .hero-cta-primary { background:linear-gradient(135deg,#fbbf24,#f59e0b); color:#1e293b; box-shadow:0 8px 28px rgba(251,191,36,0.45); }
        .hero-cta-primary:hover { transform:translateY(-3px); box-shadow:0 14px 36px rgba(251,191,36,0.55); }
        .hero-cta-secondary { background:rgba(255,255,255,0.12); color:#fff; border:1.5px solid rgba(255,255,255,0.3); backdrop-filter:blur(8px); }
        .hero-cta-secondary:hover { background:rgba(255,255,255,0.2); transform:translateY(-2px); }
        .tag { display:inline-block; padding:2px 10px; border-radius:20px; font-size:10px; font-weight:700; letter-spacing:0.06em; }
        .tag-event { background:#dbeafe; color:#1d4ed8; }
        .tag-important { background:#fee2e2; color:#dc2626; }
        .tag-holiday { background:#d1fae5; color:#059669; }
        .tag-admission { background:#ede9fe; color:#7c3aed; }
        input:focus, textarea:focus { outline:none; border-color:#1960a3 !important; }
      `}</style>

      {/* ── NAVBAR ── */}
      <nav style={{
        position: 'fixed', top: 0, left: 0, right: 0, zIndex: 100,
        padding: scrolled ? '12px 0' : '18px 0',
        background: scrolled ? 'rgba(255,255,255,0.97)' : 'transparent',
        backdropFilter: scrolled ? 'blur(16px)' : 'none',
        boxShadow: scrolled ? '0 2px 20px rgba(0,0,0,0.08)' : 'none',
        transition: 'all 0.3s ease',
        borderBottom: scrolled ? '1px solid rgba(0,0,0,0.06)' : 'none',
      }}>
        <div style={{ maxWidth: 1200, margin: '0 auto', padding: '0 24px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          {/* Logo */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
            <div style={{
              width: 40, height: 40, borderRadius: 10,
              background: scrolled ? 'linear-gradient(135deg,#002045,#1960a3)' : 'rgba(255,255,255,0.15)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              border: scrolled ? 'none' : '1.5px solid rgba(255,255,255,0.3)',
            }}>
              <Icon name="school" size={20} style={{ color: '#fff' }} />
            </div>
            <div>
              <div style={{ fontFamily: 'Manrope,sans-serif', fontWeight: 900, fontSize: 14, color: scrolled ? '#002045' : '#fff', lineHeight: 1.1, letterSpacing: '-0.01em' }}>LORD KRISHNA</div>
              <div style={{ fontSize: 9, fontWeight: 700, color: scrolled ? '#1960a3' : 'rgba(255,255,255,0.7)', letterSpacing: '0.12em', textTransform: 'uppercase' }}>PUBLIC SCHOOL</div>
            </div>
          </div>

          {/* Desktop links */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 32 }} className="desktop-nav">
